import React from "react";
import { useNavigate } from "react-router-dom";

import PageContainer from "@/components/layout/PageContainer";
import { PAGE_CONTAINER_LOADING_CLASS } from "@/components/layout/pageLoadingLayout";
import Loader from "@/components/primitives/Loader";
import DashboardTabPageHeader from "@/components/dashboard/DashboardTabPageHeader";
import { useProfile } from "@/hooks";
import { usePageTitle } from "@/hooks/usePageTitle";
import EditProfileForm from "@/sections/profile/EditProfileForm";

/** Matches `TerminalPage` main surface + tab panel padding. */
const mainSurfaceClass =
  "min-h-screen min-w-0 overflow-x-hidden focus:outline-none";

const tabPanelPad = "px-1 pb-6 pt-5 md:px-4";

const ProfileEditPage: React.FC = () => {
  const navigate = useNavigate();
  const { profile, isRegistered, loading } = useProfile();

  usePageTitle("Edit profile — Zap402");

  React.useEffect(() => {
    if (!loading && (!isRegistered || !profile)) {
      navigate("/terminal/home", { replace: true });
    }
  }, [isRegistered, profile, loading, navigate]);

  if (loading) {
    return (
      <PageContainer maxWidth="editorial" className={PAGE_CONTAINER_LOADING_CLASS}>
        <Loader size="lg" text="Loading profile…" />
      </PageContainer>
    );
  }

  if (!isRegistered || !profile) {
    return null;
  }

  return (
    <div
      tabIndex={-1}
      className={mainSurfaceClass}
      style={{ backgroundColor: "var(--color-bg)" }}
    >
      <div className="w-full min-w-0 space-y-8 py-8 pb-24 md:pb-10">
        <div className={tabPanelPad}>
          <div className="kofi-dashboard-card space-y-4 p-5 shadow-none md:p-6">
            <DashboardTabPageHeader
              kicker="Profile"
              title="Edit profile"
              description="Update your display name, bio, photo, and X handle. Your username and public link stay the same."
            />
            <EditProfileForm profile={profile} />
          </div>
        </div>
      </div>
    </div>
  );
};

export default ProfileEditPage;
